// Live Clock 12 Hour Clock

function updateClock(){

const now=new Date();

let hours=now.getHours();
let minutes=now.getMinutes();
let seconds=now.getSeconds();

let ampm=hours>=12?"PM":"AM";

hours=hours%12;
hours=hours?hours:12;

if(hours<10)hours="0"+hours;
if(minutes<10)minutes="0"+minutes;
if(seconds<10)seconds="0"+seconds;

document.getElementById("clock").innerHTML=
hours+":"+minutes+":"+seconds+" "+ampm;

}

setInterval(updateClock,1000);
updateClock();



// English Date

function getEnglishDate(){

const today=new Date();

const days=[
"Sunday","Monday","Tuesday",
"Wednesday","Thursday",
"Friday","Saturday"
];

const months=[
"January","February","March",
"April","May","June",
"July","August","September",
"October","November","December"
];

let dayName=days[today.getDay()];
let date=today.getDate();
let month=months[today.getMonth()];
let year=today.getFullYear();

document.getElementById("english-date").innerHTML=
dayName+", "+date+" "+month+" "+year;

}

getEnglishDate();



// Bangla Date

function getBanglaDate(){

const banglaMonths=[
"বৈশাখ","জ্যৈষ্ঠ","আষাঢ়","শ্রাবণ",
"ভাদ্র","আশ্বিন","কার্তিক","অগ্রহায়ণ",
"পৌষ","মাঘ","ফাল্গুন","চৈত্র"
];

const banglaWeek=[
"রবিবার","সোমবার","মঙ্গলবার",
"বুধবার","বৃহস্পতিবার",
"শুক্রবার","শনিবার"
];

const totalDays=[
31,31,31,31,31,31,
30,30,30,30,29,30
];

const today=new Date();

let day=today.getDate();
let month=today.getMonth()+1;
let year=today.getFullYear();

function isLeapYear(y){
return (y%4===0&&y%100!==0)||(y%400===0);
}

if(isLeapYear(year)){
totalDays[10]=30;
}

let banglaYear=
(month<4||(month===4&&day<14))
?year-594
:year-593;

let epochYear=
(month<4||(month===4&&day<14))
?year-1
:year;

const start=new Date(epochYear,3,13);
const current=new Date(year,month-1,day);

let diff=Math.floor(
(current-start)/(1000*60*60*24)
);

let banglaMonthIndex=0;

for(let i=0;i<banglaMonths.length;i++){

if(diff<=totalDays[i]){
banglaMonthIndex=i;
break;
}

diff-=totalDays[i];

}

function toBanglaNumber(num){

return num.toString()
.replace(/0/g,"০")
.replace(/1/g,"১")
.replace(/2/g,"২")
.replace(/3/g,"৩")
.replace(/4/g,"৪")
.replace(/5/g,"৫")
.replace(/6/g,"৬")
.replace(/7/g,"৭")
.replace(/8/g,"৮")
.replace(/9/g,"৯");

}

let weekDay=
banglaWeek[today.getDay()];

document.getElementById("bangla-date").innerHTML=

toBanglaNumber(diff)+" "+
banglaMonths[banglaMonthIndex]+", "+
toBanglaNumber(banglaYear)+
" ("+weekDay+")";

}

getBanglaDate();


